import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        a = [int(next(it)) for _ in range(N)]
        l, r = 0, N - 1
        left_max = right_max = 0
        ans = 0
        while l <= r:
            if a[l] <= a[r]:
                if a[l] >= left_max:
                    left_max = a[l]
                else:
                    ans += left_max - a[l]
                l += 1
            else:
                if a[r] >= right_max:
                    right_max = a[r]
                else:
                    ans += right_max - a[r]
                r -= 1
        out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

